<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
    max-width: 820px;
    margin: 0 auto;
    padding: 24px 16px 60px;
    background: #f5f6f8;
    color: #1c2230;
  }
  h1 { font-size: 1.5rem; margin: 0 0 20px; }
  h2 { font-size: 1.1rem; margin: 24px 0 12px; }
  .card {
    background: #fff;
    border: 1px solid #e2e5ea;
    border-radius: 10px;
    padding: 18px;
    margin-bottom: 20px;
  }
  .row { display: flex; flex-wrap: wrap; gap: 12px; }
  .field { display: flex; flex-direction: column; gap: 4px; flex: 1 1 130px; }
  label { font-size: 0.78rem; color: #55606f; font-weight: 600; }
  input, select {
    padding: 8px 10px;
    border: 1px solid #ccd1da;
    border-radius: 6px;
    font-size: 0.95rem;
    background: #fff;
  }
  button {
    cursor: pointer;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 600;
  }
  #add-expense {
    background: #2b6cff;
    color: #fff;
    padding: 10px 20px;
    margin-top: 12px;
  }
  #add-expense:hover { background: #1f57d6; }
  #form-error { color: #c62828; font-size: 0.85rem; margin-top: 10px; min-height: 1.1em; }

  .summary { display: flex; flex-wrap: wrap; gap: 12px; align-items: center; }
  #total-wrap { font-size: 1.15rem; font-weight: 700; }
  #total { color: #2b6cff; }
  .cat-total {
    background: #eef2fb;
    border: 1px solid #dbe3f5;
    border-radius: 20px;
    padding: 4px 12px;
    font-size: 0.82rem;
  }

  table { width: 100%; border-collapse: collapse; }
  th, td { text-align: left; padding: 9px 8px; border-bottom: 1px solid #eceef2; font-size: 0.92rem; }
  th { font-size: 0.75rem; text-transform: uppercase; color: #7a828f; letter-spacing: 0.5px; }
  td.amt { font-variant-numeric: tabular-nums; font-weight: 600; }
  .cat-badge {
    display: inline-block;
    padding: 2px 9px;
    border-radius: 12px;
    background: #eef2fb;
    font-size: 0.78rem;
    text-transform: capitalize;
  }
  .exp-del {
    background: #fdecec;
    color: #c62828;
    padding: 5px 10px;
  }
  .exp-del:hover { background: #f9d5d5; }
  .empty { color: #8b93a1; text-align: center; padding: 20px; font-style: italic; }
</style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <div class="card">
    <h2 style="margin-top:0">Add Expense</h2>
    <form id="expense-form" novalidate>
      <div class="row">
        <div class="field">
          <label for="amount">Amount</label>
          <input type="number" id="amount" step="0.01" placeholder="0.00">
        </div>
        <div class="field">
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div class="field">
          <label for="date">Date</label>
          <input type="date" id="date">
        </div>
        <div class="field">
          <label for="note">Note (optional)</label>
          <input type="text" id="note" placeholder="e.g. weekly shop">
        </div>
      </div>
      <button type="submit" id="add-expense">Add Expense</button>
      <div id="form-error"></div>
    </form>
  </div>

  <div class="card">
    <h2 style="margin-top:0">Filters</h2>
    <div class="row">
      <div class="field">
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">All</option>
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select>
      </div>
      <div class="field">
        <label for="filter-from">From</label>
        <input type="date" id="filter-from">
      </div>
      <div class="field">
        <label for="filter-to">To</label>
        <input type="date" id="filter-to">
      </div>
    </div>
  </div>

  <div class="card">
    <div class="summary">
      <div id="total-wrap">Total: <span id="total">0.00</span></div>
      <div id="cat-totals" class="summary"></div>
    </div>

    <h2>Expenses</h2>
    <table>
      <thead>
        <tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr>
      </thead>
      <tbody id="expense-list"></tbody>
    </table>
    <div id="empty-msg" class="empty" style="display:none">No expenses to show.</div>
  </div>

<script>
(function () {
  "use strict";

  var CATEGORIES = ["groceries", "transport", "bills", "fun"];
  var STORAGE_KEY = "expense-tracker-v1";

  var expenses = load();

  // --- Elements ---
  var form = document.getElementById("expense-form");
  var amountEl = document.getElementById("amount");
  var categoryEl = document.getElementById("category");
  var dateEl = document.getElementById("date");
  var noteEl = document.getElementById("note");
  var errorEl = document.getElementById("form-error");

  var filterCatEl = document.getElementById("filter-category");
  var filterFromEl = document.getElementById("filter-from");
  var filterToEl = document.getElementById("filter-to");

  var listEl = document.getElementById("expense-list");
  var totalEl = document.getElementById("total");
  var catTotalsEl = document.getElementById("cat-totals");
  var emptyMsg = document.getElementById("empty-msg");

  // default the entry date to today
  dateEl.value = new Date().toISOString().slice(0, 10);

  // --- Persistence ---
  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var data = JSON.parse(raw);
      return Array.isArray(data) ? data : [];
    } catch (e) {
      return [];
    }
  }
  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (e) { /* ignore quota errors */ }
  }

  // --- Add ---
  form.addEventListener("submit", function (e) {
    e.preventDefault();
    errorEl.textContent = "";

    var raw = amountEl.value.trim();
    var amount = Number(raw);

    if (raw === "" || isNaN(amount)) {
      errorEl.textContent = "Please enter a numeric amount.";
      return;
    }
    if (amount <= 0) {
      errorEl.textContent = "Amount must be greater than zero.";
      return;
    }
    if (!dateEl.value) {
      errorEl.textContent = "Please choose a date.";
      return;
    }

    expenses.push({
      id: "e" + expenses.length + "-" + expenses.reduce(function (m, x) {
        return Math.max(m, (x.seq || 0) + 1);
      }, 1),
      seq: nextSeq(),
      amount: amount,
      category: categoryEl.value,
      date: dateEl.value,
      note: noteEl.value.trim()
    });

    save();
    errorEl.textContent = "";
    amountEl.value = "";
    noteEl.value = "";
    amountEl.focus();
    render();
  });

  var seqCounter = expenses.reduce(function (m, x) {
    return Math.max(m, x.seq || 0);
  }, 0);
  function nextSeq() { seqCounter += 1; return seqCounter; }

  // --- Delete (event delegation) ---
  listEl.addEventListener("click", function (e) {
    var btn = e.target.closest(".exp-del");
    if (!btn) return;
    var id = btn.getAttribute("data-id");
    expenses = expenses.filter(function (x) { return x.id !== id; });
    save();
    render();
  });

  // --- Filters ---
  [filterCatEl, filterFromEl, filterToEl].forEach(function (el) {
    el.addEventListener("change", render);
    el.addEventListener("input", render);
  });

  function passesFilter(exp) {
    var cat = filterCatEl.value;
    if (cat !== "all" && exp.category !== cat) return false;
    var from = filterFromEl.value;
    var to = filterToEl.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  // --- Render ---
  function render() {
    // newest first: sort by seq descending (falls back to insertion order)
    var sorted = expenses.slice().sort(function (a, b) {
      return (b.seq || 0) - (a.seq || 0);
    });

    var visible = sorted.filter(passesFilter);

    listEl.innerHTML = "";
    var total = 0;
    var catTotals = {};
    CATEGORIES.forEach(function (c) { catTotals[c] = 0; });

    visible.forEach(function (exp) {
      total += exp.amount;
      if (catTotals.hasOwnProperty(exp.category)) {
        catTotals[exp.category] += exp.amount;
      }

      var tr = document.createElement("tr");
      tr.className = "expense";

      var tdAmt = document.createElement("td");
      tdAmt.className = "amt";
      tdAmt.textContent = exp.amount.toFixed(2);

      var tdCat = document.createElement("td");
      var badge = document.createElement("span");
      badge.className = "cat-badge";
      badge.textContent = exp.category;
      tdCat.appendChild(badge);

      var tdDate = document.createElement("td");
      tdDate.textContent = exp.date;

      var tdNote = document.createElement("td");
      tdNote.textContent = exp.note || "";

      var tdDel = document.createElement("td");
      var del = document.createElement("button");
      del.type = "button";
      del.className = "exp-del";
      del.setAttribute("data-id", exp.id);
      del.textContent = "Delete";
      tdDel.appendChild(del);

      tr.appendChild(tdAmt);
      tr.appendChild(tdCat);
      tr.appendChild(tdDate);
      tr.appendChild(tdNote);
      tr.appendChild(tdDel);
      listEl.appendChild(tr);
    });

    emptyMsg.style.display = visible.length ? "none" : "block";

    totalEl.textContent = total.toFixed(2);

    catTotalsEl.innerHTML = "";
    CATEGORIES.forEach(function (c) {
      var span = document.createElement("span");
      span.className = "cat-total";
      span.setAttribute("data-cat", c);
      span.textContent = c + ": " + catTotals[c].toFixed(2);
      catTotalsEl.appendChild(span);
    });
  }

  render();
})();
</script>
</body>
</html>
